import {
  EmailOutlined,
  Lock,
  RemoveRedEye,
  VisibilityOff,
} from '@mui/icons-material';
import {
  Box,
  Button,
  FormControl,
  IconButton,
  InputAdornment,
  OutlinedInput,
  Stack,
  Typography,
} from '@mui/material';
import moment from 'moment';
import Image from 'next/image';
import { FormEvent, type ReactElement, useEffect, useState } from 'react';
import { useEffectOnce, useInterval } from 'react-use';

import CriticalError from '@/components/common/critical-error';
import { StyledLink } from '@/components/common/styled-link';
import ValidationError from '@/components/common/validation-error';
import AppConstants from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import SigningLayout from '@/layouts/signing.layout';
import { ServiceError } from '@/services/errors/service-error';
import { store, useSelector } from '@/store';
import { actions as sessionStorageActions } from '@/store/slices/session-storage.slice';
import { formatDuration } from '@/utils/formatter';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';
import { MathUtil } from '@/utils/math.util';
import { validateRedirectUrl } from '@/utils/redirect-validator';

export default function Page() {
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [error, setError] = useState<ServiceError | null>(null);
  const [signinInfo, setSigninInfo] = useState<{
    email: string;
    password: string;
  }>({
    email: '',
    password: '',
  });
  const { router, services, reloader, dispatch } = useServicesHook();
  const [isPasswordShown, setIsPasswordShown] = useState<boolean>(false);
  const currentUser = useSelector((state) => state.user.me);
  const loginStatus = useSelector((state) => state.user.loginStatus);
  const [resendCooldownTime, setResendCooldownTime] = useState(0); // in seconds
  const [emailToResend, setEmailToResend] = useState('');
  const [showUiForEmailResend, setShowUiForEmailResend] = useState(false);

  const onSubmitButtonClicked = async (
    e: FormEvent<HTMLFormElement | HTMLAnchorElement>,
  ) => {
    e.preventDefault();
    await wrapForLoading(setIsSubmitting, async () => {
      setError(null);
      setShowUiForEmailResend(false);

      const result = await services.default.auth.signin(
        signinInfo.email,
        signinInfo.password,
      );
      if (result.error) {
        // the_email_is_not_confirmed
        if (result.error.code === 'E-SATH-CAS-001') {
          // * If the cooldown is already in progress, do not update the cooldown.
          // * This cooldown is not saved to the global store.
          setResendCooldownTime((time) => (time ? time : 60)); // 1 minute
          setEmailToResend(signinInfo.email);
          setShowUiForEmailResend(true);
        }
        setError(result.error);
        return;
      }
      // use location.href instead of using state management
      // so that the browser safely update all data related credentials
      const callbackUrl = router.query.callbackUrl as string | undefined;
      const safeUrl = validateRedirectUrl(callbackUrl);
      location.href = safeUrl;
    });
  };

  const onResendEmailButtonClicked = async () => {
    await wrapForLoading(setIsSubmitting, async () => {
      const result = await services.default.user.signupResend(emailToResend);
      if (result.error) {
        setError(result.error);
        return;
      }
      const resendCooldownTime = 300; // 5 minute
      setResendCooldownTime(resendCooldownTime);
      dispatch(
        sessionStorageActions.setEmailCanBeResentAfter(
          moment().add(resendCooldownTime, 'seconds').toDate(),
        ),
      );
    });
  };

  useEffectOnce(() => {
    const emailCanBeResentAfter =
      store.getState().sessionStorage.emailCanBeResentAfter;
    if (emailCanBeResentAfter) {
      const resendCooldownTime = moment(emailCanBeResentAfter).diff(
        moment(),
        'seconds',
      );
      setResendCooldownTime(MathUtil.clamp(0, resendCooldownTime, 300));
    }
  });

  useInterval(
    () => {
      setResendCooldownTime((time) => time - 1);
    },
    resendCooldownTime ? 1000 : null,
  );

  useEffect(() => {
    if (currentUser && currentUser.profile && loginStatus == 'yes') {
      const callbackUrl = router.query.callbackUrl as string | undefined;
      const safeUrl = validateRedirectUrl(callbackUrl);
      router.replace(safeUrl);
      return;
    }
    reloader.reloadIfNeeded();
  }, [currentUser]);

  return (
    <Box
      sx={{
        '.data-error': {
          p: 0.5,
        },
      }}
    >
      <form onSubmit={onSubmitButtonClicked}>
        <Stack
          direction="column"
          alignItems="center"
          sx={{
            px: { xs: 2, sm: 12 },
            py: { xs: 6, sm: 12 },
          }}
        >
          <Image
            src={AppConstants.LOGO_URL}
            alt=""
            priority={true}
            height="80"
            width="300"
          />
          <Box sx={{ px: 1, width: 1 }}>
            <Typography sx={{ mt: 12 }} variant="h2">
              {translate('login')}
            </Typography>
          </Box>
          <Box sx={{ width: 1 }}>
            <FormControl fullWidth size="small" sx={{ mt: 6 }}>
              <OutlinedInput
                name="email"
                placeholder={translate('email')}
                startAdornment={
                  <InputAdornment position="start">
                    <EmailOutlined />
                  </InputAdornment>
                }
                value={signinInfo.email}
                onChange={(x) =>
                  setSigninInfo({ ...signinInfo, email: x.target.value })
                }
              />
              <ValidationError error={error} pos={['email']} />
            </FormControl>
            <FormControl fullWidth size="small" sx={{ mt: 2 }}>
              <OutlinedInput
                name="password"
                placeholder={translate('password')}
                startAdornment={
                  <InputAdornment position="start">
                    <Lock />
                  </InputAdornment>
                }
                type={isPasswordShown ? 'text' : 'password'}
                value={signinInfo.password}
                endAdornment={
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => {
                        setIsPasswordShown(!isPasswordShown);
                      }}
                    >
                      {isPasswordShown ? <VisibilityOff /> : <RemoveRedEye />}
                    </IconButton>
                  </InputAdornment>
                }
                onChange={(x) =>
                  setSigninInfo({ ...signinInfo, password: x.target.value })
                }
              />
              <ValidationError error={error} pos={['password']} />
            </FormControl>
            <CriticalError error={error} />
            {showUiForEmailResend && (
              <Button
                loading={isSubmitting}
                onClick={onResendEmailButtonClicked}
                disabled={!!resendCooldownTime}
                variant="text"
              >
                {translate('resend_invitation_email')}
                {!!resendCooldownTime &&
                  ' (' +
                    translate('email_can_be_resent_in', {
                      time: formatDuration(resendCooldownTime),
                    }) +
                    ')'}
              </Button>
            )}
            <Button
              color="primary"
              fullWidth
              loading={isSubmitting}
              size="large"
              sx={{ mt: 4 }}
              type="submit"
              variant="contained"
            >
              {translate('button_login')}
            </Button>
          </Box>
          <Box sx={{ py: 2, width: 1 }}>
            <StyledLink
              href={PAGE_INFO.RECOVER_BY_EMAIL.href()}
              underline="hover"
            >
              {translate('forgot_password')}
            </StyledLink>
          </Box>
          {/* <Box sx={{ width: '100%', py: 2 }}>
            <Link href={PAGE_INFO.SIGN_UP.href()}>
              <Button
                sx={{ mt: 4 }}
                type="submit"
                color="success"
                variant="solid"
                size="lg"
                fullWidth
              >{translate('create_new_account')}</Button>
            </Link>
          </Box> */}
        </Stack>
      </form>
    </Box>
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <SigningLayout>{page}</SigningLayout>;
};

