import { EmailOutlined } from '@mui/icons-material';
import {
  Box,
  Button,
  FormControl,
  InputAdornment,
  OutlinedInput,
  Stack,
  Typography,
} from '@mui/material';
import moment from 'moment';
import Image from 'next/image';
import Link from 'next/link';
import { enqueueSnackbar } from 'notistack';
import { FormEvent, type ReactElement, useEffect, useState } from 'react';
import { useEffectOnce, useInterval } from 'react-use';

import CriticalError from '@/components/common/critical-error';
import ValidationError from '@/components/common/validation-error';
import AppConstants from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import SigningLayout from '@/layouts/signing.layout';
import { ServiceError } from '@/services/errors/service-error';
import { store, useSelector } from '@/store';
import { actions as sessionStorageActions } from '@/store/slices/session-storage.slice';
import { formatDuration } from '@/utils/formatter';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';
import { logger } from '@/utils/logger';
import { MathUtil } from '@/utils/math.util';

export default function Page() {
  const { dispatch } = useServicesHook();

  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [signinInfo, setSigninInfo] = useState<{ email: string }>({
    email: '',
  });
  const [error, setError] = useState<ServiceError | null>(null);
  const { router, services } = useServicesHook();
  const currentUser = useSelector((state) => state.user.me);
  const loginStatus = useSelector((state) => state.user.loginStatus);
  const [isResendFirst, setIsResendFirst] = useState(true);
  const [resendCooldownTime, setResendCooldownTime] = useState(0); // in seconds

  const onSubmitButtonClicked = async (
    e: FormEvent<HTMLFormElement | HTMLAnchorElement>,
  ) => {
    e.preventDefault();

    await wrapForLoading(setIsSubmitting, async () => {
      const result = await services.default.auth.sendPasswordResetEmail(
        signinInfo.email,
      );

      if (result.error) {
        setError(result.error);
        return;
      }

      enqueueSnackbar({
        variant: 'success',
        message: translate('email_changing_confirmation_link_sent', {
          email: signinInfo.email,
        }),
      });

      setIsResendFirst(false);
      const resendCooldownTime = isResendFirst
        ? 60 // 1 minute
        : 300; // 5 minutes
      setResendCooldownTime(resendCooldownTime);
      dispatch(
        sessionStorageActions.setEmailCanBeResentAfter(
          moment().add(resendCooldownTime, 'seconds').toDate(),
        ),
      );
    });
  };

  useEffectOnce(() => {
    const emailCanBeResentIn =
      store.getState().sessionStorage.emailCanBeResentAfter;
    if (emailCanBeResentIn) {
      const resendCooldownTime = moment(emailCanBeResentIn).diff(
        moment(),
        'seconds',
      );
      setResendCooldownTime(MathUtil.clamp(0, resendCooldownTime, 300));
    }
  });

  useInterval(
    () => {
      setResendCooldownTime((time) => time - 1);
    },
    resendCooldownTime ? 1000 : null,
  );

  useEffect(() => {
    if (currentUser && loginStatus == 'yes') {
      logger.debug('SI: already logged in - redirect to top');
      router.replace(PAGE_INFO.TOP.href());
    }
  }, [currentUser]);

  return (
    <Box
      sx={{
        '.data-error': {
          p: 0.5,
        },
      }}
    >
      <form onSubmit={onSubmitButtonClicked}>
        <Stack
          direction="column"
          alignItems="center"
          sx={{
            px: { xs: 2, sm: 12 },
            py: { xs: 6, sm: 12 },
          }}
        >
          <Image
            src={AppConstants.LOGO_URL}
            alt=""
            priority={true}
            height="80"
            width="300"
          />
          <Box sx={{ px: 1, width: 1 }}>
            <Typography textAlign="left" sx={{ mt: 12 }} variant="h2">
              {translate('account_recovery')}
            </Typography>
            <Typography textAlign="left">
              {translate('a_link_will_be_sent')}
            </Typography>
          </Box>
          <Box sx={{ mt: 4, width: 1 }}>
            <FormControl fullWidth size="small">
              <OutlinedInput
                placeholder={translate('email')}
                type="email"
                startAdornment={
                  <InputAdornment position="start">
                    <EmailOutlined />
                  </InputAdornment>
                }
                onChange={(x) =>
                  setSigninInfo({ ...signinInfo, email: x.target.value })
                }
              />
              <ValidationError error={error} pos={['email']} />
            </FormControl>
            {/* <Box sx={{ py: 4 }}>
              <MuiLink component="span">Resend recovery link</MuiLink>
            </Box> */}
            <CriticalError error={error} />
            <Button
              color="primary"
              disabled={!signinInfo.email || resendCooldownTime != 0}
              fullWidth
              loading={isSubmitting}
              size="large"
              sx={{ mt: 4 }}
              type="submit"
              variant="contained"
            >
              {translate('button_send')}
              {!!resendCooldownTime &&
                ' (' +
                  translate('email_can_be_resent_in', {
                    time: formatDuration(resendCooldownTime),
                  }) +
                  ')'}
            </Button>
            <Button
              LinkComponent={Link}
              color="neutral"
              href={PAGE_INFO.SIGN_IN.href()}
              fullWidth
              size="large"
              sx={{ mt: 2 }}
              variant="outlined"
            >
              {translate('button_back')}
            </Button>
          </Box>
        </Stack>
      </form>
    </Box>
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <SigningLayout>{page}</SigningLayout>;
};

