import type { PayloadAction } from '@reduxjs/toolkit';
import { createSlice } from '@reduxjs/toolkit';
import _ from 'lodash';

interface SessionStorageDataState {
  emailCanBeResentAfter?: Date;
}

const enum SessionStorageKey {
  EMAIL_CAN_BE_RESENT_AFTER = 'SmartScout.EmailCanBeResentAfter',
}

const parseDate = (date: string | null) => {
  if (date) {
    const dateObj = new Date(date);
    if (!Number.isNaN(dateObj.getTime())) {
      return dateObj;
    }
  }
  return undefined;
};

const getSessionStorage = (): Storage | null => {
  if (typeof sessionStorage === 'object') {
    return sessionStorage;
  }
  return null;
};

const createInitialState = (): SessionStorageDataState => {
  const sessionStorage = getSessionStorage();
  if (!sessionStorage) {
    return {};
  }

  return {
    emailCanBeResentAfter: parseDate(
      sessionStorage.getItem(SessionStorageKey.EMAIL_CAN_BE_RESENT_AFTER),
    ),
  };
};

const slice = createSlice({
  name: 'sessionStorage',
  initialState: createInitialState,
  reducers: {
    setEmailCanBeResentAfter(
      state: SessionStorageDataState,
      action: PayloadAction<Date>,
    ): void {
      state.emailCanBeResentAfter = action.payload;
      sessionStorage.setItem(
        SessionStorageKey.EMAIL_CAN_BE_RESENT_AFTER,
        action.payload.toISOString(),
      );
    },
  },
});

export const { reducer, actions } = slice;

