     1→import { AuthError, fetchAuthSession, signIn, signOut } from 'aws-amplify/auth';
     2→import _ from 'lodash';
     3→import { ZodError } from 'zod';
     4→
     5→import { ApiClient } from '@/services/clients/web-api-client';
     6→import { CodedSystemError } from '@/services/errors/coded-system-error';
     7→import { ServiceError } from '@/services/errors/service-error';
     8→import { AuthApiInterface } from '@/services/interfaces/auth-api.interface';
     9→import { translate } from '@/utils/i18n';
    10→import { logger } from '@/utils/logger';
    11→import { signinValidator } from '@/validations/auth';
    12→
    13→export type AccountVerificationStatus =
    14→  | 'unknown'
    15→  | 'not_verified'
    16→  | 'verified'
    17→  | 'not_created';
    18→
    19→export class AuthService extends ApiClient implements AuthApiInterface {
    20→  static readonly code = 'SATH';
    21→
    22→  async hasApiCredentials() {
    23→    const authSession = await fetchAuthSession();
    24→    return !!authSession.tokens?.accessToken;
    25→  }
    26→
    27→  async signOut() {
    28→    try {
    29→      // Cognito
    30→      await signOut({ global: false });
    31→    } catch (e) {
    32→      // Even if an error occurs, the token will be deleted as normal, so we
    33→      // can safely ignore it.
    34→      logger.error('unexpected error on signOut', e);
    35→    }
    36→  }
    37→
    38→  async signin(
    39→    email: string,
    40→    password: string,
    41→  ): Promise<{
    42→    error: ServiceError | null;
    43→  }> {
    44→    try {
    45→      signinValidator.parse({
    46→        email,
    47→        password,
    48→      });
    49→    } catch (e) {
    50→      const _err = e as ZodError;
    51→      for (const issue of _err.issues) {
    52→        if (
    53→          issue.path[0] == 'password' &&
    54→          (issue.code == 'too_small' || issue.code == 'too_big')
    55→        ) {
    56→          issue.message = translate('incorrect_password');
    57→        }
    58→      }
    59→      return {
    60→        error: new ServiceError(_err),
    61→      };
    62→    }
    63→
    64→    // Cognito
    65→    try {
    66→      // If user is already signed in, UserAlreadyAuthenticatedException will
    67→      // occurs when we call signIn(), so sign out first.
    68→      if (await this.hasApiCredentials()) {
    69→        // Amplify SDK is implemented to automatically clear the token store
    70→        // even when sign-out operation fails, so if the user was already
    71→        // signed in when signing in, we only need to call signOut().
    72→        await this.signOut();
    73→      }
    74→
    75→      const { isSignedIn } = await signIn({
    76→        username: email,
    77→        password,
    78→        options: {
    79→          authFlowType: 'USER_PASSWORD_AUTH',
    80→        },
    81→      });
    82→      // 必ずtrueのはず、falseになるのは2段階認証有効時など追加のアクションが必要な場合
    83→      logger.debug(`isSignedIn: ${isSignedIn}`);
    84→    } catch (e) {
    85→      if (e instanceof AuthError) {
    86→        // パスワード不一致
    87→        const isPasswordIncorrect =
    88→          // User Poolにユーザが存在
    89→          e.name === 'NotAuthorizedException' ||
    90→          // APIサーバにユーザが存在: Migration用ユーザデータは存在するがパスワードが違う
    91→          (e.name === 'UserNotFoundException' &&
    92→            e.message ===
    93→              'UserMigration failed with error Incorrect password.');
    94→
    95→        // ユーザは削除前のため休止状態である
    96→        const isHibernatedUser =
    97→          e.name === 'UserLambdaValidationException' &&
    98→          e.message === 'PreAuthentication failed with error Hibernated user.';
    99→
   100→        // User PoolにもAPIサーバにもユーザが不存在
   101→        const isUserNotFound =
   102→          e.name === 'UserNotFoundException' && !isPasswordIncorrect;
   103→
   104→        logger.error(
   105→          `AuthError: ${e}, ` +
   106→            `isPasswordIncorrect: ${isPasswordIncorrect}, ` +
   107→            `isHibernatedUser: ${isHibernatedUser}, ` +
   108→            `isUserNotFound: ${isUserNotFound}`,
   109→        );
   110→
   111→        if (isPasswordIncorrect) {
   112→          return {
   113→            error: new ServiceError(
   114→              new CodedSystemError(
   115→                AuthService.code,
   116→                'SI',
   117→                '001',
   118→                translate('incorrect_password'),
   119→              ),
   120→            ),
   121→          };
   122→        }
   123→        if (isHibernatedUser) {
   124→          return {
   125→            error: new ServiceError(
   126→              new CodedSystemError(
   127→                AuthService.code,
   128→                'SI',
   129→                '002',
   130→                translate('account_not_exists'), // 表示上は「アカウント不存在」とする
   131→              ),
   132→            ),
   133→          };
   134→        }
   135→        if (isUserNotFound) {
   136→          return this.checkAccountStatus(email);
   137→        }
   138→
   139→        return {
   140→          error: new ServiceError(
   141→            new CodedSystemError(
   142→              AuthService.code,
   143→              'SI',
   144→              '003',
   145→              translate('failed_to_authenticate_for_unknown_reason'),
   146→            ),
   147→          ),
   148→        };
   149→      }
   150→    }
   151→
   152→    return {
   153→      error: null,
   154→    };
   155→  }
   156→
   157→  private async checkAccountStatus(email: string) {
   158→    const { result, errors } = await this.wrapForApiError(async () => {
   159→      return await this.client.get<{ status: AccountVerificationStatus }>(
   160→        `auth/users/verification-status`,
   161→        {
   162→          params: {
   163→            email,
   164→          },
   165→        },
   166→      );
   167→    });
   168→
   169→    if (result?.status == 'not_verified') {
   170→      return {
   171→        error: new ServiceError(
   172→          // When updating this, make sure that to update signin.tsx.
   173→          new CodedSystemError(
   174→            AuthService.code,
   175→            'CAS',
   176→            '001',
   177→            translate('the_email_is_not_confirmed'),
   178→          ),
   179→        ),
