const formatTimeComponent = (timeComponent: number) => {
  return timeComponent.toString().padStart(2, '0');
};

export const formatDuration = (seconds: number) => {
  const minutes = Math.floor(seconds / 60);
  const moduloSeconds = seconds % 60;
  return `${formatTimeComponent(minutes)}:${formatTimeComponent(moduloSeconds)}`;
